var Axiom=class{constructor(){this.components={};this.initializedComponents=new Map();document.addEventListener("DOMContentLoaded",()=> this.init());}registerComponent(componentName,componentDefinition){if(!componentName || typeof componentName !=="string"){console.error("Axiom:registerComponent requires a valid component name.");return false;}const isClass=typeof componentDefinition==="function" &&
 /^\s*class\s/.test(componentDefinition.toString());const isInitObject=typeof componentDefinition==="object" &&
 componentDefinition !==null &&
 typeof componentDefinition.init==="function";if(!isClass && !isInitObject){console.error(`Axiom:Invalid component definition for ${componentName}. Expected class or object with init(element).`);return false;}this.components[componentName]=componentDefinition;return true;}getComponent(componentName){return this.components[componentName]|| null;}listComponents(){return Object.keys(this.components);}async loadComponent(componentName){if(this.components[componentName]){return this.components[componentName];}const componentPath=`./components/${componentName}.js`;try{const module=await import(componentPath);if(module.default){if(typeof module.default==="function" &&
 /^\s*class\s/.test(module.default.toString())){this.components[componentName]=module.default;return module.default;}if(typeof module.default==="object" &&
 typeof module.default.init==="function"){this.components[componentName]=module.default;return module.default;}}console.error(`Axiom:Component ${componentName}does not have a valid default export(class or object with init method).`);return null;}catch(error){console.error(`Axiom:Failed to load component ${componentName}.`,error);return null;}}async init(){console.log("Axiom:Initializing...");const componentElements=document.querySelectorAll("[data-component]");const loadPromises=[];const uniqueComponents=new Set();componentElements.forEach((element)=>{const componentName=element.dataset.component;if(componentName && !uniqueComponents.has(componentName)){uniqueComponents.add(componentName);loadPromises.push(this.loadComponent(componentName));}});await Promise.all(loadPromises);componentElements.forEach((element)=>{const componentName=element.dataset.component;const ComponentDefinition=this.components[componentName];if(componentName && ComponentDefinition){try{let componentInstance=null;if(typeof ComponentDefinition==="function" &&
 /^\s*class\s/.test(ComponentDefinition.toString())){componentInstance=new ComponentDefinition(element);}else if(typeof ComponentDefinition==="object" &&
 typeof ComponentDefinition.init==="function"){componentInstance=ComponentDefinition.init(element);}if(componentInstance && typeof componentInstance.destroy==="function"){this.initializedComponents.set(element,{name:componentName,instance:componentInstance,});}console.log(`Axiom:Initialized component:${componentName}on`,element);}catch(error){console.error(`Axiom:Error initializing component ${componentName}on element:`,element,error);}}});console.log("Axiom:Initialization complete.");}destroyComponent(element){if(this.initializedComponents.has(element)){const{name,instance}=this.initializedComponents.get(element);if(instance && typeof instance.destroy==="function"){try{instance.destroy();console.log(`Axiom:Destroyed component:${name}on`,element);}catch(error){console.error(`Axiom:Error destroying component ${name}on element:`,element,error);}}this.initializedComponents.delete(element);}}destroyAllComponents(){this.initializedComponents.forEach((_value,element)=>{this.destroyComponent(element);});this.initializedComponents.clear();console.log("Axiom:All components destroyed.");}};window.Axiom=new Axiom();window.Axiom.dismiss=function(element){if(!element)return;element.style.transition='opacity 0.25s cubic-bezier(0.4,0,0.2,1),transform 0.25s cubic-bezier(0.4,0,0.2,1)';element.style.opacity='0';element.style.transform='scale(0.95)';element.addEventListener('transitionend',function(){element.remove();},{once:true});};window.Axiom.setActiveStep=function(stepsContainer,targetIndex){const steps=stepsContainer.querySelectorAll('span');if(targetIndex < 0 || targetIndex >=steps.length)return;steps.forEach((step,idx)=>{if(idx===targetIndex){step.setAttribute('data-active','true');step.removeAttribute('data-completed');}else if(idx < targetIndex){step.removeAttribute('data-active');step.setAttribute('data-completed','true');}else{step.removeAttribute('data-active');step.removeAttribute('data-completed');}});const event=new CustomEvent('axiomStepChange',{detail:{activeIndex:targetIndex,activeStep:steps[targetIndex]},bubbles:true});stepsContainer.dispatchEvent(event);};window.Axiom.initHierarchyAccessibility=function(hierarchyContainer){const items=hierarchyContainer.querySelectorAll('a,summary,.hierarchy-item');items.forEach((item,index)=>{item.setAttribute('tabindex','0');item.addEventListener('keydown',function(e){let target=null;switch(e.key){case 'ArrowDown':e.preventDefault();target=items[index + 1]|| items[0];break;case 'ArrowUp':e.preventDefault();target=items[index - 1]|| items[items.length - 1];break;case 'ArrowRight':if(item.tagName==='SUMMARY'){const details=item.parentNode;if(details && !details.open){e.preventDefault();details.open=true;}}break;case 'ArrowLeft':if(item.tagName==='SUMMARY'){const details=item.parentNode;if(details && details.open){e.preventDefault();details.open=false;}}break;}if(target){target.focus();}});});};document.addEventListener('DOMContentLoaded',function(){document.addEventListener('click',function(e){const closeBtn=e.target.closest('.alert[data-dismiss="alert"],.alert .close');if(closeBtn){e.preventDefault();const alert=closeBtn.closest('.alert');window.Axiom.dismiss(alert);}});document.addEventListener('click',function(e){const stepNode=e.target.closest('.steps span');if(stepNode){const parent=stepNode.closest('.steps');if(parent){const steps=Array.from(parent.querySelectorAll('span'));const index=steps.indexOf(stepNode);window.Axiom.setActiveStep(parent,index);}}});document.addEventListener('click',function(e){const tabLink=e.target.closest('.tabs nav a');if(tabLink){e.preventDefault();const parent=tabLink.closest('.tabs');if(!parent)return;parent.querySelectorAll('nav a').forEach(a=> a.removeAttribute('data-active'));parent.querySelectorAll('section').forEach(s=> s.style.display='none');tabLink.setAttribute('data-active','true');const targetId=tabLink.getAttribute('href').replace('#','');const targetSection=parent.querySelector('#' + targetId);if(targetSection){targetSection.style.display='block';}}});document.addEventListener('focusin',function(e){const fieldWrapper=e.target.closest('.field,.pager li');if(fieldWrapper){fieldWrapper.setAttribute('data-focused','true');}});document.addEventListener('focusout',function(e){const fieldWrapper=e.target.closest('.field,.pager li');if(fieldWrapper){fieldWrapper.removeAttribute('data-focused');}});window.addEventListener('click',function(){document.querySelectorAll('.popover[aria-expanded="true"]').forEach(function(popover){popover.setAttribute('aria-expanded','false');});document.querySelectorAll('details.dropbutton-details[open]').forEach(function(dropbutton){dropbutton.removeAttribute('open');});});window.addEventListener('keydown',function(e){if(e.key==='Escape'){document.querySelectorAll('details[open]').forEach(function(details){details.removeAttribute('open');});document.querySelectorAll('dialog[open]').forEach(function(dialog){dialog.removeAttribute('open');if(typeof dialog.close==='function'){dialog.close();}});}});});(function(){'use strict';const THEME_KEY='theme';const DARK_THEME='dark';const LIGHT_THEME='light';function initTheme(){const currentTheme=document.documentElement.getAttribute('data-theme');if(currentTheme){return;}let savedTheme=localStorage.getItem(THEME_KEY);if(!savedTheme){const prefersDark=window.matchMedia && window.matchMedia('(prefers-color-scheme:dark)').matches;savedTheme=prefersDark?DARK_THEME:LIGHT_THEME;}setTheme(savedTheme);}function setTheme(theme){document.documentElement.setAttribute('data-theme',theme);localStorage.setItem(THEME_KEY,theme);updateThemeIcon(theme);}function getTheme(){return document.documentElement.getAttribute('data-theme')|| LIGHT_THEME;}function toggleTheme(){const current=getTheme();const next=current===DARK_THEME?LIGHT_THEME:DARK_THEME;setTheme(next);}function updateThemeIcon(theme){const themeButtons=document.querySelectorAll('button.theme');themeButtons.forEach(btn=>{const icon=btn.querySelector('.axicon');if(icon){const iconName=theme===DARK_THEME?'Sun':'Moon';icon.setAttribute('data-name',iconName);if(typeof renderAxicons !=='undefined'){setTimeout(renderAxicons,0);}}});}document.addEventListener('DOMContentLoaded',function(){initTheme();const isIndexPage=window.location.pathname.includes('index.html')|| window.location.pathname.endsWith('/');if(!isIndexPage){const themeButtons=document.querySelectorAll('button.theme');themeButtons.forEach(btn=>{btn.addEventListener('click',function(e){e.preventDefault();toggleTheme();});});}});window.AXIOM_THEME={setTheme,getTheme,toggleTheme,init:initTheme};})();